#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int A, B; scanf("%d %d", &A, &B);
        if(A>0 && B>0) printf("Solution\n");
        else if(B==0) printf("Solid\n");
        else printf("Liquid\n");
    }
    return 0;
}

