import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out = []
    for _ in range(t):
        a = int(data[idx]); b = int(data[idx+1]); idx += 2
        if a > 0 and b > 0:
            out.append('Solution')
        elif b == 0:
            out.append('Solid')
        else:
            out.append('Liquid')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

